#!/usr/bin/env node
/**
 * Reapply the vendored scratch-render patch after `npm install`.
 *
 * The vendored scratch-vm and scratch-render are tracked outside the main
 * dependency tree (see vendored/ in .gitignore). We carry a targeted source
 * patch against vendored/scaffolding/node_modules/scratch-render (see
 * patches/scratch-render+0.1.0.patch) that we reapply here so the
 * `vendored/scaffolding/dist/scaffolding-min.js` UMD never needs to be
 * regenerated by hand after a fresh checkout.
 *
 * The patch adds two guards against a "Failed to construct 'ImageData':
 * The source height is zero or not a number" DOMException that aborts
 * loadProject() when a custom extension drives the stage size to 0 during
 * load. See `src/runtime/player.ts` (formerly had a dangling
 * docs/extension-imagedata-investigation.md reference) for context.
 *
 * Behavior:
 *   - If vendored/scaffolding/node_modules/scratch-render is not installed
 *     yet (e.g. the user has not run `cd vendored/scaffolding && npm install`),
 *     this script exits 0 with a hint. Re-run it once vendored deps are in
 *     place.
 *   - patch-package is invoked from vendored/scaffolding so its package
 *     resolution works against that local node_modules tree.
 *   - The patches/ directory lives at the project root so it stays under
 *     version control (vendored/ is gitignored).
 *
 * Exit code:
 *   - 0 on success
 *   - 0 with a `console.warn` if the vendored scratch-render isn't installed
 *     yet (nothing to patch against)
 *   - non-zero (postinstall propagates) if patch-package fails. We do NOT
 *     swallow the failure — a malformed patch in this directory once
 *     caused scratch-render to ship without the ImageData guards and
 *     every project that drove stage size to 0 during load failed with
 *     `Failed to load project: Failed to construct 'ImageData'...`.
 *
 * Escape hatch:
 *   - Set `SKIP_VENDORED_PATCHES=1` (or any non-empty value) to opt out.
 *     Useful for `npm install --ignore-scripts` users who manually manage
 *     the vendored tree.
 */

import { spawnSync } from 'node:child_process';
import { existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const root = resolve(here, '..');
const patchesDir = resolve(root, 'patches');
const scaffoldingDir = resolve(root, 'vendored', 'scaffolding');
const renderPkg = resolve(scaffoldingDir, 'node_modules', 'scratch-render', 'package.json');

if (process.env.SKIP_VENDORED_PATCHES && process.env.SKIP_VENDORED_PATCHES !== '0') {
  console.warn('[apply-vendored-patches] SKIP_VENDORED_PATCHES is set; skipping.');
  process.exit(0);
}

if (!existsSync(renderPkg)) {
  console.warn(
    '[apply-vendored-patches] vendored/scaffolding/node_modules/scratch-render not installed; skipping.\n' +
      '                Run `cd vendored/scaffolding && npm install`, then re-run `npm run apply:scratch-render-patch`.',
  );
  process.exit(0);
}

// patch-package resolves --patch-dir relative to the app root it discovers
// (vendored/scaffolding), so we pass the relative path from there.
const relativePatchesDir = '../../patches';

const result = spawnSync(
  process.execPath,
  [resolve(root, 'node_modules', 'patch-package', 'index.js'), '--patch-dir', relativePatchesDir],
  {
    cwd: scaffoldingDir,
    stdio: 'inherit',
    shell: false,
  },
);

if (result.status !== 0) {
  console.error(
    `[apply-vendored-patches] patch-package exited with code ${result.status}. ` +
      'The vendored scratch-render was NOT patched. Aborting npm install so the ' +
      'broken state is visible. Common causes: malformed patch file (missing blank ' +
      'line between hunks, trailing newline, or out-of-date context), or a vendored ' +
      'scratch-render version that no longer matches patches/scratch-render+0.1.0.patch. ' +
      'Run `git apply --check -p1 -v patches/scratch-render+0.1.0.patch` from ' +
      'vendored/scaffolding to diagnose. Set SKIP_VENDORED_PATCHES=1 to opt out.',
  );
  process.exit(result.status);
}

console.log('[apply-vendored-patches] vendored scratch-render patches applied.');